    private static List<T> AssignRanks<T, TKey>(IEnumerable<T> rows, Func<T, TKey> tieKeySelector, Func<T, int, T> ranker)
    {
        var rankedRows = new List<T>();
        var comparer = EqualityComparer<TKey>.Default;
        var previousKey = default(TKey);
        var currentRank = 0;
        var position = 0;
        var hasPreviousKey = false;

        foreach (var row in rows)
        {
            position++;
            var currentKey = tieKeySelector(row);

            if (!hasPreviousKey || !comparer.Equals(previousKey, currentKey))
            {
                currentRank = position;
                previousKey = currentKey;
                hasPreviousKey = true;
            }

            rankedRows.Add(ranker(row, currentRank));
        }

        return rankedRows;
    }
